actions.script:
import groovy.json.JsonOutput
import groovy.json.JsonSlurper
import java.net.http.HttpClient
import java.net.http.HttpRequest
import java.net.http.HttpResponse
import java.time.Duration

success = false
publishedUrl = null
externalPostId = null
errorMessage = null

try {
    def sessionToken = platformConfig.apiKey
    if (!sessionToken) {
        errorMessage = "Substack session token (apiKey) not configured"
        return
    }

    def notesBaseUrl = (System.getProperty('growerp.substack.notesBaseUrl') ?:
        'https://substack.com').replaceAll('/+$', '')

    // Prosemirror doc: blank-line separated paragraphs (same as article publisher)
    def paragraphs = (post.finalContent as String).split(/\n\n+/).collect { para ->
        def lines = para.trim()
        if (!lines) return null
        [type: "paragraph", content: [[type: "text", text: lines]]]
    }.findAll { it != null }
    if (!paragraphs) {
        paragraphs = [[type: "paragraph", content: [[type: "text", text: post.finalContent as String]]]]
    }

    def requestBody = [
        bodyJson: [type: "doc", attrs: [schemaVersion: "v1"], content: paragraphs],
        tabId: "for-you",
        surface: "feed",
        replyMinimumRole: "everyone"
    ]

    def httpClient = HttpClient.newBuilder()
        .connectTimeout(Duration.ofSeconds(15))
        .build()

    def request = HttpRequest.newBuilder()
        .uri(URI.create("${notesBaseUrl}/api/v1/comment/feed"))
        .header("Content-Type", "application/json")
        .header("Cookie", "substack.sid=${sessionToken}; connect.sid=${sessionToken}")
        .header("Referer", notesBaseUrl)
        .header("Origin", notesBaseUrl)
        .POST(HttpRequest.BodyPublishers.ofString(JsonOutput.toJson(requestBody)))
        .timeout(Duration.ofSeconds(30))
        .build()

    def response = httpClient.send(request, HttpResponse.BodyHandlers.ofString())
    def responseBody = response.body()

    ec.logger.info("Substack note response [${response.statusCode()}]: ${responseBody?.take(500)}")

    if (response.statusCode() in [200, 201]) {
        def parsed = new JsonSlurper().parseText(responseBody)
        externalPostId = parsed?.id as String
        publishedUrl = externalPostId ? "${notesBaseUrl}/note/c-${externalPostId}" : notesBaseUrl
        success = true
    } else {
        errorMessage = "Substack note API error ${response.statusCode()}: ${responseBody?.take(300)}"
    }
} catch (Exception e) {
    errorMessage = "Substack note publishing failed: ${e.message}"
    ec.logger.error("Substack note publish error", e)
}

import groovy.json.JsonOutput
import java.net.http.HttpClient
import java.net.http.HttpRequest
import java.net.http.HttpResponse
import java.time.Duration

success = false
errorMessage = null

try {
    def publicationUrl = platformConfig.username?.replaceAll('/+$', '')
    if (!publicationUrl) {
        errorMessage = "Substack publication URL (username) not configured"
        return
    }

    def httpClient = HttpClient.newBuilder()
        .connectTimeout(Duration.ofSeconds(15))
        .build()

    def request = HttpRequest.newBuilder()
        .uri(URI.create("${publicationUrl}/api/v1/free"))
        .header("Content-Type", "application/json")
        .header("Referer", publicationUrl)
        .header("Origin", publicationUrl)
        .POST(HttpRequest.BodyPublishers.ofString(JsonOutput.toJson([email: emailAddress])))
        .timeout(Duration.ofSeconds(30))
        .build()

    def response = httpClient.send(request, HttpResponse.BodyHandlers.ofString())
    def responseBody = response.body()

    ec.logger.info("Substack subscribe response [${response.statusCode()}] for " +
        "${emailAddress}: ${responseBody?.take(300)}")

    if (response.statusCode() in [200, 201]) {
        success = true
    } else {
        errorMessage = "Substack subscribe error ${response.statusCode()}: ${responseBody?.take(300)}"
    }
} catch (Exception e) {
    errorMessage = "Substack subscribe failed: ${e.message}"
    ec.logger.error("Substack subscribe error", e)
}

import groovy.json.JsonSlurper
import java.net.http.HttpClient
import java.net.http.HttpRequest
import java.net.http.HttpResponse
import java.time.Duration

comments = []
errorMessage = null

try {
    def publicationUrl = platformConfig.username?.replaceAll('/+$', '')
    if (!publicationUrl) {
        errorMessage = "Substack publication URL (username) not configured"
        return
    }
    def sessionToken = platformConfig.apiKey

    def httpClient = HttpClient.newBuilder()
        .connectTimeout(Duration.ofSeconds(15))
        .build()

    def builder = HttpRequest.newBuilder()
        .uri(URI.create("${publicationUrl}/api/v1/post/${externalPostId}/comments?all_comments=true"))
        .header("Referer", publicationUrl)
        .GET()
        .timeout(Duration.ofSeconds(30))
    if (sessionToken) {
        builder.header("Cookie", "substack.sid=${sessionToken}; connect.sid=${sessionToken}")
    }

    def response = httpClient.send(builder.build(), HttpResponse.BodyHandlers.ofString())
    if (!(response.statusCode() in [200, 201])) {
        errorMessage = "Substack comments API error ${response.statusCode()}: " +
            "${response.body()?.take(300)}"
        return
    }

    def parsed = new JsonSlurper().parseText(response.body())
    def flatten
    flatten = { List nodes ->
        for (node in nodes) {
            if (node == null) continue
            comments.add([
                externalId:     node.id as String,
                userName:       node.name ?: node.user_name ?: 'Anonymous',
                userProfileUrl: node.handle ? "https://substack.com/@${node.handle}" : null,
                body:           node.body,
                date:           node.date ?: node.created_at,
                type:           node.type ?: 'comment'
            ])
            if (node.children) flatten(node.children)
        }
    }
    flatten(parsed?.comments ?: [])
} catch (Exception e) {
    errorMessage = "Substack comments fetch failed: ${e.message}"
    ec.logger.error("Substack comments fetch error", e)
}
